+                .metadata
+                .get("created_ts")
+                .and_then(serde_json::Value::as_i64);
+            let subject = hit
+                .metadata
+                .get("subject")
+                .and_then(|v| v.as_str())
+                .unwrap_or("")
+                .to_string();
+
+            PlannerResult {
+                doc_kind,
+                id: hit.doc_id,
+                project_id: hit
+                    .metadata
+                    .get("project_id")
+                    .and_then(serde_json::Value::as_i64),
+                title: subject,
+                body: hit.snippet.clone().unwrap_or_default(),
+                score: Some(hit.score),
+                importance,
+                ack_required: None, // not in Tantivy index
+                created_ts,
+                thread_id,
+                from_agent,
+                redacted: false,
+                redaction_reason: None,
+            }
+        })
+        .collect()
+}

